+    #[test]
+    fn compile_restart_ops_one_for_all() {
+        init_test("compile_restart_ops_one_for_all");
+
+        let compiled = SupervisorBuilder::new("test")
+            .with_restart_policy(RestartPolicy::OneForAll)
